const monto = parseFloat($json.monto || 0);
const plazo = parseInt($json.plazo || 0);

// Lógica de Tasa Escalonada
let tasaAnual;

if (plazo <= 12) {
  tasaAnual = 0.12; // 12% anual si es a un año o menos (Interés Bajo)
} else if (plazo <= 36) {
  tasaAnual = 0.18; // 18% anual si es de 1 a 3 años (Interés Medio)
} else {
  tasaAnual = 0.25; // 25% anual si es a más de 3 años (Interés Alto)
}

const tasaMensual = tasaAnual / 12;

// Fórmula de cuota nivelada (Sistema Francés)
// cuota = (P * i) / (1 - (1+i)^-n)
const cuota = (monto * tasaMensual) / (1 - Math.pow(1 + tasaMensual, -plazo));

const totalAPagar = cuota * plazo;
const interesTotal = totalAPagar - monto;
return [{
  ...$json,
  analisis_financiero: {
    tasa_anual_aplicada: (tasaAnual * 100) + "%",
    cuota_mensual: parseFloat(cuota.toFixed(2)),
    total_a_pagar: parseFloat(totalAPagar.toFixed(2)),
    interes_puro: parseFloat(interesTotal.toFixed(2)),
    plazo_meses: plazo
  }
}];

let aprobado = true;
let razones = [];

// 🔹 DATOS
const ingreso = $json.contrato?.total_mensual || 0;
const monto = parseFloat($json.monto || 0);
const plazo = parseInt($json.plazo || 0);

// 🔹 VALIDACIONES BÁSICAS
if (!monto || monto <= 0) {
  aprobado = false;
  razones.push("Monto inválido");
}

if (!plazo || plazo <= 0) {
  aprobado = false;
  razones.push("Plazo inválido");
}

if (!ingreso || ingreso <= 0) {
  aprobado = false;
  razones.push("Ingreso inválido");
}

// 🔹 CAPACIDAD DE PAGO (30%)
const capacidadMax = ingreso * 0.3;

// 🔹 ESTIMACIÓN SIMPLE (SIN INTERÉS)
const pagoEstimado = monto / plazo;

// 🔹 VALIDACIÓN PRINCIPAL 🔥
if (pagoEstimado > capacidadMax) {
  aprobado = false;
  razones.push("El plazo seleccionado no permite cubrir el crédito con su ingreso");
}

// 🔹 VALIDACIÓN MONTO MÁXIMO
const montoMax = ingreso * 20;

if (monto > montoMax) {
  aprobado = false;
  razones.push("Monto demasiado alto para su nivel de ingresos");
}

// 🔹 RESULTADO
return [{
  ...$json,
  aprobado,
  capacidad_pago: capacidadMax,
  pago_estimado: pagoEstimado,
  monto_maximo_permitido: montoMax,
  razones
}];

function limpiar(texto) {
  return (texto || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

// ===== DATOS FORMULARIO =====
const nombreForm = limpiar($json.nombre);
const apellidoForm = limpiar($json.apellidos);
const nombreCompletoForm = limpiar($json.nombre + " " + $json.apellidos);
const dpiForm = ($json.numero_dpi || "").replace(/\s+/g, "");
const telefono = ($json.telefono || "").replace(/\s+/g, "");
const sueldoForm = parseFloat($json.sueldo || 0);

// ===== DOCUMENTOS =====
const dpi = $json.dpi || {};
const contrato = $json.contrato || {};
const factura = $json.factura || {};
const ref_fam = $json.ref_fam || {};

// ===== DATOS LIMPIOS =====
const nombreDPI = limpiar(dpi.nombres);
const apellidoDPI = limpiar(dpi.apellidos);
const dpiDoc = dpi.cui;

const nombreContrato = limpiar(contrato.nombre_completo);
const dpiContrato = contrato.numero_dpi;
const sueldoContrato = contrato.total_mensual || 0;

const nombreFactura = limpiar(factura.nombre_cliente);

const nombreRef = limpiar(ref_fam.nombre_completo);
const dpiRef = ref_fam.numero_dpi;

// ===== VALIDACIONES =====
let coincidencias = 0;
let razones = [];

// 🧾 NOMBRE
if (nombreDPI.includes(nombreForm)) {
  coincidencias++;
} else {
  razones.push("Nombre no coincide con DPI");
}

// 🧾 APELLIDO
if (apellidoDPI.includes(apellidoForm)) {
  coincidencias++;
} else {
  razones.push("Apellido no coincide con DPI");
}

// 🆔 DPI
if (dpiForm === dpiDoc) {
  coincidencias++;
} else {
  razones.push("DPI no coincide");
}

// 📄 CONTRATO
if (dpiContrato && dpiContrato !== dpiDoc) {
  razones.push("DPI en contrato no coincide");
}

if (nombreContrato && !nombreContrato.includes(nombreForm)) {
  razones.push("Nombre en contrato no coincide");
}

// 💰 SUELDO
if (sueldoForm !== sueldoContrato) {
  razones.push("El sueldo declarado no coincide con el contrato");
}

// 🧾 FACTURA
if (nombreFactura && !nombreFactura.includes(nombreForm)) {
  razones.push("Nombre en factura no coincide");
}

// 👨‍👩‍👧 REFERENCIA FAMILIAR
if (dpiRef && dpiRef === dpiDoc) {
  razones.push("Referencia familiar inválida (misma persona)");
}

if (nombreRef && nombreRef === nombreCompletoForm) {
  razones.push("Referencia familiar no puede ser el mismo solicitante");
}

// 📱 TELÉFONO
if (!/^\d{8}$/.test(telefono)) {
  razones.push("Teléfono inválido");
}

// ===== RESULTADO FINAL =====
const identidad_valida = coincidencias >= 3;
const datos_consistentes = razones.length === 0;

return [{
  ...$json,
  identidad_válida: identidad_valida,
  datos_consistentes,
  coincidencias,
  razones,
  aprobado: identidad_valida && datos_consistentes
}];

function limpiar(texto) {
  if (!texto || typeof texto !== "string") return null;

  try {
    texto = texto.replace(/```json|```/g, "").trim();
    return JSON.parse(texto);
  } catch (e) {
    return null;
  }
}

// 🔹 limpiar todo correctamente
const contrato = limpiar($json.contrato);
const ref_fam = limpiar($json.fam);
const dpi = limpiar($json.dpsol);
const factura = limpiar($json.factura);

return [{
  ...$json,
  contrato,
  ref_fam,
  dpi,
  factura
}];
